const CosmosClient = require("@azure/cosmos").CosmosClient; // this import is used to connect to azure cosmos db.
// This code will be executed at startup of the function for every invocation.
async function main(context, documents) {
    const config = context.bindings.config; 
    const client = new CosmosClient(config); // here we are using context object that comes as argument in our azure function to provide credentials and key.
    try{
        //here we are looping through our documents
        for (const document of documents){

            //getting the item ID
            const itemId = document._id; 
            let res;
            if (!document) {
                continue; 
            
            } else {
                // Here, we call an API for fetching the total count of the items.
                await fetch('https://localhost:8096/api/Count/'+itemId).then(response => response.json()) //this is a fetch API which will hit our API to get the total count 
                .then(data => {
                    res = data;
                });
            }
        } 
        return 200;
    } catch (err){
        console.log(`Error in main function ${err}`);
        throw err;
    }
} // here we are using async await to wait until fetch completes before continuing with the code that is inside try block after the for loop


module.exports = main;